INSERT OR IGNORE INTO entities ("id", "agent_id", "type", "name", "properties", "first_seen", "last_seen", "status", "machine_id", "synced_at") VALUES ('43da3870-bd15-41da-870e-0c73930a747b', 'myco-agent', 'component', 'Cloudflare Worker', '{"description":"The Worker relay in unifi-mcp-worker. Exposes MCP tools via HTTP (stateless handler). Contains no UniFi domain logic — acts purely as a relay. Uses a Durable Object for stateful coordination. Framework-free by architectural invariant.","project":"unifi-mcp-worker"}', 1774735416, 1774735416, 'active', 'local', NULL);
INSERT OR IGNORE INTO entities ("id", "agent_id", "type", "name", "properties", "first_seen", "last_seen", "status", "machine_id", "synced_at") VALUES ('866dc2af-c098-4e9e-acf8-f01f73a41cc4', 'myco-agent', 'component', 'CLI workspace', '{"description":"The CLI workspace in unifi-mcp-worker. Owns all UniFi domain logic. Has its own TypeScript project, test suite, and node_modules — intentionally isolated from the Worker workspace. No shared build step with the Worker.","project":"unifi-mcp-worker"}', 1774735417, 1774735417, 'active', 'local', NULL);
INSERT OR IGNORE INTO entities ("id", "agent_id", "type", "name", "properties", "first_seen", "last_seen", "status", "machine_id", "synced_at") VALUES ('532bc0a4-6918-4b9f-b023-b38435cad31f', 'myco-agent', 'concept', 'two-workspace architecture', '{"description":"Architectural pattern in unifi-mcp-worker: CLI workspace (domain logic) and Worker workspace (relay) are kept strictly separate. No merged node_modules, no shared build steps, independent test suites. Enforced as a non-goal invariant in AGENTS.md."}', 1774735419, 1774735419, 'active', 'local', NULL);

